  1→import type {
  2→  LegacySubmission,
  3→  PointEvent,
  4→  PointEventType,
  5→  ProjectedPoint,
  6→  SubmissionCategory,
  7→  SubmissionDetails,
  8→  SubmissionLocation,
  9→} from "../../shared/types.js";
 10→import { getVertical } from "../../shared/verticals.js";
 11→
 12→function trimString(input: unknown): string | undefined {
 13→  if (typeof input !== "string") return undefined;
 14→  const trimmed = input.trim();
 15→  return trimmed || undefined;
 16→}
 17→
 18→function hasValue(input: unknown): boolean {
 19→  if (typeof input === "string") return Boolean(input.trim());
 20→  if (typeof input === "number") return Number.isFinite(input);
 21→  if (typeof input === "boolean") return true;
 22→  if (Array.isArray(input)) return input.length > 0;
 23→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 24→  return false;
 25→}
 26→
 27→function normalizeDetailsForCategory(category: SubmissionCategory, raw: SubmissionDetails): SubmissionDetails {
 28→  return getVertical(category).normalizeDetails(raw);
 29→}
 30→
 31→function mergeDetails(base: SubmissionDetails, incoming: SubmissionDetails): SubmissionDetails {
 32→  const merged: SubmissionDetails = { ...base };
 33→  const entries = Object.entries(incoming) as Array<[string, unknown]>;
 34→  for (const [key, value] of entries) {
 35→    if (!hasValue(value)) continue;
 36→    if (Array.isArray(value)) {
 37→      merged[key] = value;
 38→      continue;
 39→    }
 40→    if (typeof value === "object" && value !== null && !Array.isArray(value)) {
 41→      const prev = merged[key];
 42→      if (typeof prev === "object" && prev !== null && !Array.isArray(prev)) {
 43→        merged[key] = { ...(prev as Record<string, unknown>), ...(value as Record<string, unknown>) };
 44→      } else {
 45→        merged[key] = value;
 46→      }
 47→      continue;
 48→    }
 49→    merged[key] = value;
 50→  }
 51→  return merged;
 52→}
 53→
 54→export function listMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
 55→  const normalized = normalizeDetailsForCategory(category, details);
 56→  return getVertical(category).enrichableFields.filter((field) => !hasValue(normalized[field]));
 57→}
 58→
 59→export function listCreateMissingFields(category: SubmissionCategory, details: SubmissionDetails): string[] {
 60→  const normalized = normalizeDetailsForCategory(category, details);
 61→  return getVertical(category).createRequiredFields.filter((field) => !hasValue(normalized[field]));
 62→}
 63→
 64→export function isEnrichFieldAllowed(category: SubmissionCategory, field: string): boolean {
 65→  const canonicalField =
 66→    field === "merchantId"
 67→      ? "merchantIdByProvider"
 68→      : field === "hasCashAvailable"
 69→        ? "hasMin50000XafAvailable"
 70→      : field === "hours"
 71→        ? "openingHours"
 72→        : field === "isOnCall" || field === "onDuty"
 73→          ? "isOnDuty"
 74→          : field;
 75→  return getVertical(category).enrichableFields.includes(canonicalField);
 76→}
 77→
 78→export function eventToProjectedPoint(event: PointEvent): ProjectedPoint {
 79→  const details = normalizeDetailsForCategory(event.category, event.details ?? {});
 80→  const gaps = listMissingFields(event.category, details);
 81→  return {
 82→    id: event.pointId,
 83→    pointId: event.pointId,
 84→    category: event.category,
 85→    location: event.location,
 86→    details,
 87→    photoUrl: event.photoUrl,
 88→    createdAt: event.createdAt,
 89→    updatedAt: event.createdAt,
 90→    source: event.source,
 91→    externalId: event.externalId,
 92→    gaps,
 93→    eventsCount: 1,
 94→    eventIds: [event.id],
 95→  };
 96→}
 97→
 98→export function projectPointsFromEvents(events: PointEvent[]): ProjectedPoint[] {
 99→  const groups = new Map<string, ProjectedPoint>();
100→  const sorted = [...events].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
101→  for (const event of sorted) {
102→    const normalizedDetails = normalizeDetailsForCategory(event.category, event.details ?? {});
103→    const existing = groups.get(event.pointId);
104→    if (!existing) {
105→      groups.set(
106→        event.pointId,
107→        {
108→          id: event.pointId,
109→          pointId: event.pointId,
110→          category: event.category,
111→          location: event.location,
112→          details: normalizedDetails,
113→          photoUrl: event.photoUrl,
114→          createdAt: event.createdAt,
115→          updatedAt: event.createdAt,
116→          source: event.source,
117→          externalId: event.externalId,
118→          gaps: listMissingFields(event.category, normalizedDetails),
119→          eventsCount: 1,
120→          eventIds: [event.id],
121→        },
122→      );
123→      continue;
124→    }
125→
126→    existing.category = event.category;
127→    existing.location = event.location ?? existing.location;
128→    existing.details = mergeDetails(existing.details, normalizedDetails);
129→    existing.updatedAt = event.createdAt;
130→    existing.eventsCount += 1;
131→    existing.eventIds.push(event.id);
132→    if (event.photoUrl) existing.photoUrl = event.photoUrl;
133→    if (event.source) existing.source = event.source;
134→    if (event.externalId) existing.externalId = event.externalId;
135→    existing.gaps = listMissingFields(existing.category, existing.details);
136→  }
137→
138→  return Array.from(groups.values()).sort(
139→    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
140→  );
141→}
142→
143→export function projectPointById(events: PointEvent[], pointId: string): ProjectedPoint | null {
144→  return projectPointsFromEvents(events).find((point) => point.pointId === pointId) ?? null;
145→}
