147→export function legacySubmissionToCreateEvent(submission: LegacySubmission): PointEvent {
148→  const eventType: PointEventType = "CREATE_EVENT";
149→  const details = normalizeDetailsForCategory(submission.category, submission.details ?? {});
150→  const source = trimString(details.source) ?? "legacy_submission";
151→  const externalId = trimString(details.externalId) ?? `legacy:${submission.id}`;
152→  return {
153→    id: `legacy-event-${submission.id}`,
154→    pointId: submission.id,
155→    eventType,
156→    userId: submission.userId,
157→    category: submission.category,
158→    location: submission.location,
159→    details,
160→    photoUrl: submission.photoUrl,
161→    createdAt: submission.createdAt,
162→    source,
163→    externalId,
164→  };
165→}
166→
167→export function mergePointEventsWithLegacy(pointEvents: PointEvent[], legacySubmissions: LegacySubmission[]): PointEvent[] {
168→  const merged = [...pointEvents];
169→  const seen = new Set(merged.map((item) => item.id));
170→  for (const legacy of legacySubmissions) {
171→    const converted = legacySubmissionToCreateEvent(legacy);
172→    if (seen.has(converted.id)) continue;
173→    merged.push(converted);
174→    seen.add(converted.id);
175→  }
176→  return merged;
177→}
