179→export function normalizeEnrichPayload(category: SubmissionCategory, details: SubmissionDetails): SubmissionDetails {
180→  const normalized = normalizeDetailsForCategory(category, details);
181→  if (normalized.hours && !normalized.openingHours) normalized.openingHours = String(normalized.hours);
182→  return normalized;
183→}
