  1→import { createHash } from "node:crypto";
  2→import { query } from "../db.js";
  3→import type { LegacySubmission, MapScope, PointEvent, PointEventType, SubmissionCategory, UserProfile } from "../../../shared/types.js";
  4→import { isValidCategory } from "../../../shared/verticals.js";
  5→import { normalizeEmail, normalizePhone } from "../../shared/identifier.js";
  6→import type { StorageStore } from "./types.js";
  7→
  8→const VALID_MAP_SCOPES: ReadonlySet<MapScope> = new Set(["bonamoussadi", "cameroon", "global"]);
  9→let phoneColumnState: "unknown" | "present" | "missing" = "unknown";
 10→
 11→function normalizeUserId(input: string): string {
 12→  return input.toLowerCase().trim();
 13→}
 14→
 15→function normalizeMapScope(input: unknown): MapScope {
 16→  if (typeof input !== "string") return "bonamoussadi";
 17→  const normalized = input.trim().toLowerCase() as MapScope;
 18→  if (!VALID_MAP_SCOPES.has(normalized)) return "bonamoussadi";
 19→  return normalized;
 20→}
 21→
 22→function parseXp(input: unknown): number {
 23→  const value = typeof input === "number" ? input : Number(input);
 24→  if (!Number.isFinite(value)) return 0;
 25→  return Math.max(0, Math.round(value));
 26→}
 27→
 28→function isUuid(input: string): boolean {
 29→  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(input);
 30→}
 31→
 32→function deterministicUuid(seed: string): string {
 33→  const hex = createHash("sha1").update(seed).digest("hex").slice(0, 32).split("");
 34→  hex[12] = "5";
 35→  const variant = parseInt(hex[16], 16);
 36→  hex[16] = ((variant & 0x3) | 0x8).toString(16);
 37→  return `${hex.slice(0, 8).join("")}-${hex.slice(8, 12).join("")}-${hex.slice(12, 16).join("")}-${hex.slice(16, 20).join("")}-${hex.slice(20, 32).join("")}`;
 38→}
 39→
 40→function normalizeEventId(input: string): string {
 41→  const trimmed = input.trim();
 42→  if (isUuid(trimmed)) return trimmed.toLowerCase();
 43→  return deterministicUuid(`event:${trimmed}`);
 44→}
 45→
 46→function normalizeCreatedAt(input: unknown): string {
 47→  if (typeof input === "string") {
 48→    const parsed = new Date(input);
 49→    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
 50→  }
 51→  return new Date().toISOString();
 52→}
 53→
 54→function parseCategory(input: unknown): SubmissionCategory {
 55→  if (typeof input === "string" && isValidCategory(input)) return input as SubmissionCategory;
 56→  return "mobile_money";
 57→}
 58→
 59→function parseEventType(input: unknown): PointEventType {
 60→  if (input === "CREATE_EVENT" || input === "ENRICH_EVENT") return input;
 61→  return "CREATE_EVENT";
 62→}
 63→
 64→function parseLocation(input: unknown): { latitude: number; longitude: number } | null {
 65→  const raw = input as { latitude?: unknown; longitude?: unknown };
 66→  const latitude = typeof raw?.latitude === "number" ? raw.latitude : Number(raw?.latitude);
 67→  const longitude = typeof raw?.longitude === "number" ? raw.longitude : Number(raw?.longitude);
 68→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 69→  return { latitude, longitude };
 70→}
 71→
 72→function rowToUserProfile(row: Record<string, unknown>): UserProfile {
 73→  const email = typeof row.email === "string" && row.email.trim() ? row.email.toLowerCase().trim() : null;
 74→  const phone = typeof row.phone === "string" && row.phone.trim() ? row.phone.trim() : null;
 75→  return {
 76→    id: String(row.id ?? "").toLowerCase().trim(),
 77→    email,
 78→    phone,
 79→    name: typeof row.name === "string" ? row.name : "",
 80→    image: typeof row.image === "string" ? row.image : "",
 81→    occupation: typeof row.occupation === "string" ? row.occupation : "",
 82→    XP: parseXp(row.xp),
 83→    passwordHash: typeof row.password_hash === "string" ? row.password_hash : undefined,
 84→    isAdmin: Boolean(row.is_admin),
 85→    mapScope: normalizeMapScope(row.map_scope),
 86→  };
 87→}
 88→
 89→function isMissingPhoneColumnError(error: unknown): boolean {
 90→  if (!(error instanceof Error)) return false;
 91→  const pgError = error as Error & { code?: string };
 92→  const message = error.message.toLowerCase();
 93→  return pgError.code === "42703" && message.includes("phone");
 94→}
 95→
 96→async function getUserProfileLegacy(id: string): Promise<UserProfile | null> {
 97→  const result = await query<Record<string, unknown>>(
 98→    `
 99→      select id, email, name, image, occupation, xp, password_hash, is_admin, map_scope
100→      from user_profiles
101→      where id = $1
102→      limit 1
103→    `,
104→    [id],
105→  );
106→
107→  const row = result.rows[0];
108→  if (!row) return null;
109→  return rowToUserProfile(row);
110→}
111→
112→function rowToPointEvent(row: Record<string, unknown>): PointEvent {
113→  const details = row.details && typeof row.details === "object" ? (row.details as PointEvent["details"]) : {};
114→
115→  return {
116→    id: String(row.id),
117→    pointId: String(row.point_id ?? ""),
118→    eventType: parseEventType(row.event_type),
119→    userId: String(row.user_id ?? "").toLowerCase().trim(),
120→    category: parseCategory(row.category),
121→    location: {
122→      latitude: typeof row.latitude === "number" ? row.latitude : Number(row.latitude),
123→      longitude: typeof row.longitude === "number" ? row.longitude : Number(row.longitude),
124→    },
125→    details,
126→    photoUrl: typeof row.photo_url === "string" ? row.photo_url : undefined,
127→    createdAt: normalizeCreatedAt(row.created_at),
128→    source: typeof row.source === "string" ? row.source : undefined,
129→    externalId: typeof row.external_id === "string" ? row.external_id : undefined,
130→  };
131→}
132→
133→async function getUserProfile(userId: string): Promise<UserProfile | null> {
134→  const id = normalizeUserId(userId);
135→  if (phoneColumnState === "missing") {
136→    return await getUserProfileLegacy(id);
137→  }
138→
139→  try {
140→    const result = await query<Record<string, unknown>>(
141→      `
142→        select id, email, phone, name, image, occupation, xp, password_hash, is_admin, map_scope
143→        from user_profiles
144→        where id = $1
145→        limit 1
146→      `,
147→      [id],
148→    );
149→
150→    const row = result.rows[0];
151→    if (!row) return null;
152→    if (phoneColumnState === "unknown") phoneColumnState = "present";
153→    return rowToUserProfile(row);
154→  } catch (error) {
155→    if (!isMissingPhoneColumnError(error)) throw error;
156→    phoneColumnState = "missing";
157→    return await getUserProfileLegacy(id);
158→  }
159→}
