161→async function upsertUserProfileLegacy(params: {
162→  id: string;
163→  email: string | null;
164→  name: string;
165→  image: string;
166→  occupation: string;
167→  xp: number;
168→  passwordHash: string | null;
169→  isAdmin: boolean;
170→  mapScope: MapScope;
171→}): Promise<void> {
172→  const legacyEmail = params.email ?? normalizeEmail(params.id);
173→  if (!legacyEmail) {
174→    throw new Error("Database migration required: phone-only identifiers need user_profiles.phone column");
175→  }
176→
177→  await query(
178→    `
179→      insert into user_profiles (id, email, name, image, occupation, xp, password_hash, is_admin, map_scope, updated_at)
180→      values ($1, $2, $3, $4, $5, $6, $7, $8, $9, now())
181→      on conflict (id) do update
182→      set
183→        email = excluded.email,
184→        name = excluded.name,
185→        image = excluded.image,
186→        occupation = excluded.occupation,
187→        xp = excluded.xp,
188→        password_hash = coalesce(excluded.password_hash, user_profiles.password_hash),
189→        is_admin = excluded.is_admin,
190→        map_scope = excluded.map_scope,
191→        updated_at = now()
192→    `,
193→    [
194→      params.id,
195→      legacyEmail,
196→      params.name,
197→      params.image,
198→      params.occupation,
199→      params.xp,
200→      params.passwordHash,
201→      params.isAdmin,
202→      params.mapScope,
203→    ],
204→  );
205→}
