290→async function getPointEvents(): Promise<PointEvent[]> {
291→  const result = await query<Record<string, unknown>>(
292→    `
293→      select id, point_id, event_type, user_id, category, latitude, longitude, details, photo_url, created_at, source, external_id
294→      from point_events
295→      order by created_at asc
296→    `,
