302→async function insertPointEvent(event: PointEvent): Promise<void> {
303→  const id = normalizeEventId(event.id);
304→  const pointId = typeof event.pointId === "string" && event.pointId.trim() ? event.pointId.trim() : id;
305→  const eventType = parseEventType(event.eventType);
306→  const userId = normalizeUserId(event.userId || "unknown");
307→  const category = parseCategory(event.category);
308→  const location = parseLocation(event.location);
309→  if (!location) throw new Error("Invalid point event location");
310→  const details = event.details && typeof event.details === "object" ? event.details : {};
311→  const photoUrl = typeof event.photoUrl === "string" ? event.photoUrl : null;
312→  const createdAt = normalizeCreatedAt(event.createdAt);
313→  const source = typeof event.source === "string" ? event.source : null;
314→  const externalId = typeof event.externalId === "string" ? event.externalId : null;
315→
316→  await query(
317→    `
318→      insert into point_events (id, point_id, event_type, user_id, category, latitude, longitude, details, photo_url, created_at, source, external_id)
319→      values ($1::uuid, $2, $3, $4, $5, $6, $7, $8::jsonb, $9, $10::timestamptz, $11, $12)
320→      on conflict (id) do update
321→      set
322→        point_id = excluded.point_id,
323→        event_type = excluded.event_type,
324→        user_id = excluded.user_id,
325→        category = excluded.category,
326→        latitude = excluded.latitude,
327→        longitude = excluded.longitude,
328→        details = excluded.details,
329→        photo_url = excluded.photo_url,
330→        created_at = excluded.created_at,
331→        source = excluded.source,
332→        external_id = excluded.external_id
333→    `,
334→    [id, pointId, eventType, userId, category, location.latitude, location.longitude, JSON.stringify(details), photoUrl, createdAt, source, externalId],
335→  );
336→}
337→
338→async function deletePointEvent(eventId: string): Promise<boolean> {
339→  const normalizedId = normalizeEventId(eventId);
340→  const result = await query(
341→    `
342→      delete from point_events
343→      where id = $1::uuid
344→    `,
345→    [normalizedId],
346→  );
347→  return result.rowCount > 0;
348→}
349→
350→async function bulkUpsertPointEvents(events: PointEvent[]): Promise<void> {
351→  if (!events.length) return;
352→
353→  await query("begin");
354→  try {
355→    for (const event of events) {
356→      await insertPointEvent(event);
357→    }
358→    await query("commit");
359→  } catch (error) {
360→    await query("rollback");
361→    throw error;
362→  }
363→}
