  9→async function getCombinedEvents(): Promise<PointEvent[]> {
 10→  const pointEvents = await getPointEvents();
 11→  const legacySubmissions = await getLegacySubmissions();
 12→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
 13→  const seenExternalIds = new Set(
 14→    merged
 15→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
 16→      .filter((value) => value.length > 0),
 17→  );
 18→  const seenPointIds = new Set(merged.map((event) => event.pointId));
 19→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
 20→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
 21→    if (externalId && seenExternalIds.has(externalId)) continue;
 22→    if (seenPointIds.has(seedEvent.pointId)) continue;
 23→    merged.push(seedEvent);
 24→    if (externalId) seenExternalIds.add(externalId);
 25→    seenPointIds.add(seedEvent.pointId);
 26→  }
 27→  return merged;
 28→}
