115→export async function DELETE(request: Request): Promise<Response> {
116→  const auth = await requireUser(request);
117→  if (!auth) return errorResponse("Unauthorized", 401);
118→  const viewer = toSubmissionAuthContext(auth);
119→  if (!viewer) return errorResponse("Unauthorized", 401);
120→  if (!viewer.isAdmin) return errorResponse("Forbidden", 403);
121→
122→  const url = new URL(request.url);
123→  const id = url.pathname.split("/").pop();
124→  const view = url.searchParams.get("view");
125→  if (!id) return errorResponse("Missing submission id", 400);
126→  if (view !== "event") return errorResponse("Use view=event for event deletion", 400);
127→
128→  try {
129→    const deleted = await deletePointEvent(id);
130→    if (deleted) return jsonResponse({ ok: true, id }, { status: 200 });
131→
132→    const combined = await getCombinedEvents();
133→    const existsReadOnly = combined.some((event) => event.id === id);
134→    if (existsReadOnly) {
135→      return errorResponse("Submission source is read-only and cannot be deleted", 409);
136→    }
137→    return errorResponse("Submission event not found", 404);
138→  } catch (error) {
139→    if (isStorageUnavailableError(error)) {
140→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
141→    }
142→    throw error;
143→  }
144→}
