289→function mergePhotoFraudMetadata(
290→  existing: SubmissionFraudCheck["primaryPhoto"],
291→  recovered: SubmissionFraudCheck["primaryPhoto"],
292→  hasPhotoUrl: boolean,
293→): SubmissionFraudCheck["primaryPhoto"] {
294→  if (!hasPhotoUrl) return existing ?? null;
295→  if (existing && !isPhotoMetadataEffectivelyEmpty(existing)) return existing;
296→  if (recovered) return recovered;
297→  return existing ?? null;
