345→async function buildAdminSubmissionEvents(events: PointEvent[]): Promise<AdminSubmissionEvent[]> {
346→  const sortedEvents = [...events].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
347→  const userIds = Array.from(
348→    new Set(
349→      sortedEvents
350→        .map((event) => normalizeActorId(event.userId))
351→        .filter((value) => value.length > 0),
352→    ),
353→  );
354→
355→  const profileEntries = await Promise.all(
356→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
357→  );
358→  const profileByUserId = new Map(profileEntries);
359→  const output: AdminSubmissionEvent[] = [];
360→  let fallbackLookups = 0;
361→
362→  for (const event of sortedEvents) {
363→    const normalizedUserId = normalizeActorId(event.userId);
364→    const profile = profileByUserId.get(normalizedUserId) ?? null;
365→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
366→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
367→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
368→    let fraudCheck = getEventFraudCheck(event);
369→    if (shouldRunFallbackFraudCheck(event, fraudCheck) && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
370→      fallbackLookups += 1;
371→      try {
372→        fraudCheck = await buildFallbackFraudCheck(event, fraudCheck);
373→      } catch {
374→        fraudCheck = fraudCheck ?? null;
375→      }
376→    }
377→
378→    output.push({
379→      event,
380→      user: {
381→        id: normalizedUserId || event.userId,
382→        name,
383→        email,
384→      },
385→      fraudCheck,
386→    });
387→  }
388→
389→  return output;
390→}
