413→export async function GET(request: Request): Promise<Response> {
414→  const auth = await requireUser(request);
415→  const authContext = toSubmissionAuthContext(auth);
416→  const url = new URL(request.url);
417→  const view = url.searchParams.get("view");
418→  const lat = url.searchParams.get("lat");
419→  const lng = url.searchParams.get("lng");
420→  const radius = url.searchParams.get("radius");
421→  const requestedScope = normalizeMapScope(url.searchParams.get("scope"));
422→  const canUseExpandedScope = requestedScope !== "bonamoussadi";
423→  if (canUseExpandedScope && !authContext) return errorResponse("Unauthorized", 401);
424→  if (canUseExpandedScope && !authContext.isAdmin) return errorResponse("Forbidden", 403);
425→  const effectiveScope = canUseExpandedScope ? requestedScope : "bonamoussadi";
426→  const canUsePublicCache = !authContext && !canUseExpandedScope;
427→
428→  try {
429→    const allEvents = await buildCombinedEvents();
430→    const scopedEvents = allEvents.filter((event) => {
431→      if (effectiveScope === "global") return true;
432→      if (effectiveScope === "cameroon") return isWithinCameroon(event.location);
433→      return isWithinBonamoussadi(event.location);
434→    });
435→
436→    if (view === "events") {
437→      if (!authContext) {
438→        return jsonResponse(redactEventUserIds(scopedEvents), {
439→          status: 200,
440→          headers: {
441→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
442→          },
443→        });
444→      }
445→      const responseEvents = filterEventsForViewer(scopedEvents, authContext);
446→      return jsonResponse(responseEvents, { status: 200 });
447→    }
448→
449→    if (view === "admin_events") {
450→      const adminAccess = resolveAdminViewAccess(authContext);
451→      if (adminAccess === "unauthorized") return errorResponse("Unauthorized", 401);
452→      if (adminAccess === "forbidden") return errorResponse("Forbidden", 403);
453→      const adminEvents = await buildAdminSubmissionEvents(scopedEvents);
454→      return jsonResponse(adminEvents, { status: 200 });
455→    }
456→
457→    let projected = projectPointsFromEvents(scopedEvents);
458→
459→    if (lat && lng && radius) {
460→      const latitude = Number(lat);
461→      const longitude = Number(lng);
462→      const radiusKm = Number(radius);
463→      if (Number.isFinite(latitude) && Number.isFinite(longitude) && Number.isFinite(radiusKm)) {
464→        projected = projected.filter((point) => haversineKm(point.location, { latitude, longitude }) <= radiusKm);
465→      }
466→    }
467→
468→    return jsonResponse(projected, {
469→      status: 200,
470→      headers: canUsePublicCache
471→        ? {
472→            "cache-control": PUBLIC_READ_CACHE_CONTROL,
473→          }
474→        : undefined,
475→    });
476→  } catch (error) {
477→    if (isStorageUnavailableError(error)) {
478→      return errorResponse("Storage service temporarily unavailable", 503, { code: "storage_unavailable" });
479→    }
480→    throw error;
481→  }
482→}
